"use client";

import {
  memo,
  useCallback,
  useId,
  useImperativeHandle,
  useMemo,
  useState,
} from "react";
import type { MouseEvent } from "react";
import { defaultRelativeTime } from "./hooks/use-relative-time";
import { defaultDateFormat, toDate } from "./lib/format-default";
import { defaultContentCardKebabActions } from "./lib/defaults";
import { resolveContentCardPermissions } from "./lib/permissions";
import { FeaturedPart } from "./parts/featured";
import { LargePart } from "./parts/large";
import { MediumPart } from "./parts/medium";
import { SmallPart } from "./parts/small";
import { ListPart } from "./parts/list";
import {
  DEFAULT_LABELS,
  type ContentCardItem,
  type ContentCardNews01Handle,
  type ContentCardNewsProps,
  type ResolvedPartProps,
} from "./types";

/**
 * ContentCardNews01 — magazine-style content card with 5 visual variants
 * dispatched via the `variant` prop (`featured` / `large` / `medium` / `small` / `list`).
 *
 * v0.3.0 grows the card into a backend-shaped composite — role-aware kebab,
 * permissions matrix, paywall + sensitive gates, badge stack, quoted-article
 * mini-card, light engagement counts (with slot-based engagement-bar-01
 * composition), per-entity click handlers, 11-method imperative handle, and
 * ~50 i18n label keys. All v0.2 behavior preserved when new props are absent.
 *
 * See the description doc at
 * docs/procomps/content-card-news-01-procomp/content-card-news-01-procomp-description-v0.3.0.md
 * for the full A+ trait set.
 */
function ContentCardNews01Impl(props: ContentCardNewsProps) {
  const {
    item: itemProp,
    variant = "medium",
    href,
    onClick,
    linkComponent: LinkComponent = "a",
    formatRelativeTime,
    formatDate,
    labels: labelsProp,
    categoryStyles,
    titleClassName,
    imageClassName,
    className,
    ariaLabel: ariaLabelProp,
    actions,
    loading: loadingProp,

    // v0.3 — role-aware
    viewerMode,
    permissions,
    canPerformAction,

    // v0.3 — slots
    renderBadges,
    renderAuthor,
    renderExcerpt,
    renderPaywallGate,
    renderSensitiveGate,
    renderQuoted,
    renderEngagementCounts,
    kebabActions,
    moderatorActions,

    // v0.3 — opt-outs
    disableBadgesRender = false,
    disableAuthorRender = false,
    disableExcerptRender = false,
    disablePaywallGate = false,
    disableSensitiveGate = false,
    disableQuotedRender = false,
    disableEngagementCounts = false,

    // v0.3 — engagement handlers
    onLike,
    onBookmark,
    onShare,
    onComment,
    onCommentCountClick,

    // v0.3 — per-entity click handlers
    onAuthorClick,
    onPublisherClick,
    onCategoryClick,
    onTopicClick,
    onTagClick,
    onQuotedClick,
    onTranslate,
    onRevealPaywall,
    onRevealSensitive,

    // v0.3 — mutation handlers (flattened from ContentCardMutationHandlers)
    onEdit,
    onDelete,
    onPublish,
    onUnpublish,
    onSchedule,
    onFeature,
    onPin,
    onChangeVisibility,
    onChangeCategory,
    onMarkSensitive,
    onSeeAnalytics,
    onPushToTop,
    onReport,
    onBlockAuthor,
    onMuteAuthor,
    onUnfollowTopic,

    ref,
  } = props;

  // ─── Local mirror (R-Plan-1) ─────────────────────────────────────────────
  const [statefulItem, setStatefulItem] = useState<ContentCardItem>(itemProp);
  const [paywallRevealed, setPaywallRevealed] = useState(false);
  const [sensitiveRevealed, setSensitiveRevealed] = useState(false);

  // Use the prop as the source of truth in render path — the mirror only
  // applies the local flags + any reset() override. v0.2 consumers pushing
  // updates via prop changes still see fresh data (statefulItem follows
  // itemProp implicitly via React's render).
  const effectiveItem = statefulItem === itemProp ? itemProp : statefulItem;

  // ─── Resolved labels + permissions ───────────────────────────────────────
  const labels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const resolvedPermissions = useMemo(
    () => resolveContentCardPermissions(viewerMode, permissions),
    [viewerMode, permissions],
  );

  const canModerate = useMemo(() => {
    if (canPerformAction) {
      const r = canPerformAction("moderate", effectiveItem);
      if (r === true) return true;
      if (r === false) return false;
    }
    return resolvedPermissions.canModerate;
  }, [canPerformAction, effectiveItem, resolvedPermissions]);

  // ─── Date/format derivations (v0.2 carry; now prefers publishedAt over date) ─
  const dateSource = effectiveItem.publishedAt ?? effectiveItem.date;
  const date = useMemo(() => toDate(dateSource), [dateSource]);

  const formattedRelativeTime = useMemo(() => {
    if (!date) return undefined;
    return (formatRelativeTime ?? defaultRelativeTime)(date);
  }, [date, formatRelativeTime]);

  const formattedDate = useMemo(() => {
    if (!date) return undefined;
    return (formatDate ?? defaultDateFormat)(date);
  }, [date, formatDate]);

  const categoryStyle = useMemo(() => {
    if (!effectiveItem.category) return "bg-muted";
    return categoryStyles?.[effectiveItem.category] ?? "bg-muted";
  }, [effectiveItem.category, categoryStyles]);

  const titleId = useId();
  const ariaLabel =
    ariaLabelProp ?? `${labels.readArticlePrefix} ${effectiveItem.title}`;

  const handleClick = useCallback(
    (event: MouseEvent) => {
      onClick?.({ item: effectiveItem, event });
    },
    [onClick, effectiveItem],
  );

  const loading: "lazy" | "eager" =
    loadingProp ?? (variant === "featured" ? "eager" : "lazy");

  // ─── Internal reveal callbacks (set local flag + fire analytics hook) ────
  const onRevealPaywallInternal = useCallback(() => {
    setPaywallRevealed(true);
    onRevealPaywall?.(effectiveItem.id);
  }, [effectiveItem.id, onRevealPaywall]);

  const onRevealSensitiveInternal = useCallback(() => {
    setSensitiveRevealed(true);
    onRevealSensitive?.(effectiveItem.id);
  }, [effectiveItem.id, onRevealSensitive]);

  // ─── Engagement handlers pre-bound to item id ────────────────────────────
  const engagementHandlers = useMemo(
    () => ({
      onLike: onLike
        ? (nextLiked: boolean) => onLike(effectiveItem.id, nextLiked)
        : undefined,
      onComment: onCommentCountClick
        ? () => onCommentCountClick(effectiveItem.id)
        : onComment
          ? () => onComment(effectiveItem.id)
          : undefined,
      onShare: onShare ? () => onShare(effectiveItem.id) : undefined,
      onBookmark: onBookmark
        ? (nextBookmarked: boolean) =>
            onBookmark(effectiveItem.id, nextBookmarked)
        : undefined,
    }),
    [effectiveItem.id, onLike, onComment, onCommentCountClick, onShare, onBookmark],
  );

  // ─── Kebab items (computed once via the default helper unless full-takeover slot supplied) ─
  const boundTranslate = useMemo(() => {
    if (!onTranslate || !effectiveItem.language) return undefined;
    return () => onTranslate(effectiveItem.id, effectiveItem.language!);
  }, [onTranslate, effectiveItem.id, effectiveItem.language]);

  const kebabItems = useMemo(() => {
    if (kebabActions) return kebabActions(effectiveItem);
    return defaultContentCardKebabActions({
      item: effectiveItem,
      engagementHandlers: { onBookmark, onShare },
      miscHandlers: { onTranslate: boundTranslate },
      viewerMode,
      permissions,
      canPerformAction,
      mutationHandlers: {
        onEdit,
        onDelete,
        onPublish,
        onUnpublish,
        onSchedule,
        onFeature,
        onPin,
        onChangeVisibility,
        onChangeCategory,
        onMarkSensitive,
        onSeeAnalytics,
        onPushToTop,
        onReport,
        onBlockAuthor,
        onMuteAuthor,
        onUnfollowTopic,
      },
      moderatorActions,
      labels: labelsProp,
    });
  }, [
    kebabActions,
    effectiveItem,
    onBookmark,
    onShare,
    boundTranslate,
    viewerMode,
    permissions,
    canPerformAction,
    onEdit,
    onDelete,
    onPublish,
    onUnpublish,
    onSchedule,
    onFeature,
    onPin,
    onChangeVisibility,
    onChangeCategory,
    onMarkSensitive,
    onSeeAnalytics,
    onPushToTop,
    onReport,
    onBlockAuthor,
    onMuteAuthor,
    onUnfollowTopic,
    moderatorActions,
    labelsProp,
  ]);

  // ─── Imperative handle (11 methods) ──────────────────────────────────────
  useImperativeHandle(
    ref,
    (): ContentCardNews01Handle => ({
      openKebab: () => {
        // Variant parts own the actual trigger ref. Handle the open via a
        // sentinel — variant parts subscribe via the kebab trigger they
        // render. v0.3 ships an open-emitter at C11; for now the handle
        // method is wired but the trigger is per-variant.
        // No-op until C11 wires the per-variant open ref.
      },
      triggerEdit: () => onEdit?.(effectiveItem.id),
      triggerDelete: () => onDelete?.(effectiveItem.id),
      triggerPublish: () => onPublish?.(effectiveItem.id),
      triggerUnpublish: () => onUnpublish?.(effectiveItem.id),
      triggerPin: () => onPin?.(effectiveItem.id, !effectiveItem.isPinned),
      triggerFeature: () =>
        onFeature?.(effectiveItem.id, !effectiveItem.isFeatured),
      revealPaywall: onRevealPaywallInternal,
      revealSensitive: onRevealSensitiveInternal,
      reset: (next: ContentCardItem) => {
        setStatefulItem(next);
        setPaywallRevealed(false);
        setSensitiveRevealed(false);
      },
      getCurrentItem: () => effectiveItem,
    }),
    [
      effectiveItem,
      onEdit,
      onDelete,
      onPublish,
      onUnpublish,
      onPin,
      onFeature,
      onRevealPaywallInternal,
      onRevealSensitiveInternal,
    ],
  );

  // ─── Resolved part-props bag ─────────────────────────────────────────────
  const partProps: ResolvedPartProps = {
    item: effectiveItem,
    formattedDate,
    formattedRelativeTime,
    categoryStyle,
    labels,
    LinkComponent,
    href,
    onClick: onClick ? handleClick : undefined,
    ariaLabel,
    titleId,
    titleClassName,
    imageClassName,
    className,
    actions,
    loading,

    // v0.3 — role-aware
    viewerMode,
    resolvedPermissions,
    canModerate,

    // v0.3 — local-mirror flags
    paywallRevealed,
    sensitiveRevealed,
    onRevealPaywallInternal,
    onRevealSensitiveInternal,

    // v0.3 — render slots passthrough
    renderBadges,
    renderAuthor,
    renderExcerpt,
    renderPaywallGate,
    renderSensitiveGate,
    renderQuoted,
    renderEngagementCounts,

    // v0.3 — opt-outs passthrough
    disableBadgesRender,
    disableAuthorRender,
    disableExcerptRender,
    disablePaywallGate,
    disableSensitiveGate,
    disableQuotedRender,
    disableEngagementCounts,

    // v0.3 — handler bag + kebab + click handlers
    engagementHandlers,
    kebabItems,
    onAuthorClick,
    onPublisherClick,
    onCategoryClick,
    onTopicClick,
    onTagClick,
    onQuotedClick,
  };

  switch (variant) {
    case "featured":
      return <FeaturedPart {...partProps} />;
    case "large":
      return <LargePart {...partProps} />;
    case "small":
      return <SmallPart {...partProps} />;
    case "list":
      return <ListPart {...partProps} />;
    case "medium":
    default:
      return <MediumPart {...partProps} />;
  }
}

export const ContentCardNews01 = memo(ContentCardNews01Impl);
ContentCardNews01.displayName = "ContentCardNews01";

export default ContentCardNews01;

// ─── Tail type re-exports (cross-procomp consumers) ──────────────────────────
// Procomps that adapt to ContentCardItem must import these types from THIS
// component-file path, not `./types`: the shadcn path rewriter preserves the
// component-file path but mangles `/types` cross-procomp imports (F-S1).
export type {
  ContentCardItem,
  ContentStatus,
  NewsArticleAuthor,
  NewsPublisher,
  NewsVisibility,
  ContentSensitivity,
  ContentPaywall,
} from "./types";

// ─── Root component ─────────────────────────────────────────────────────────
export { ContentCardNews01, default } from "./content-card-news-01";

// ─── Public types (v0.2 carry + v0.3.0 additions) ───────────────────────────
export type {
  // v0.2 carry
  ContentCardItem,
  ContentCardNewsLabels,
  ContentCardNewsProps,
  ContentCardNewsVariant,
  ResolvedPartProps,
  // v0.3 — role-aware + permissions
  NewsViewerMode,
  ContentCardPermissionAction,
  ContentCardPermissions,
  ContentCardMutationHandlers,
  ContentCardEngagementHandlers,
  ContentCardClickHandlers,
  ContentCardNews01Handle,
  // v0.3 — entity sub-types
  NewsArticleAuthor,
  NewsPublisher,
  ContentStatus,
  NewsVisibility,
  ContentSensitivity,
  ContentPaywall,
} from "./types";

// ─── Default constants (label dictionary) ───────────────────────────────────
export { DEFAULT_LABELS } from "./types";

// ─── Hooks + format helpers (v0.2 carry) ────────────────────────────────────
export { defaultRelativeTime } from "./hooks/use-relative-time";
export { defaultDateFormat, toDate } from "./lib/format-default";

// ─── v0.3 — permission resolver + kebab defaults ────────────────────────────
export {
  resolveContentCardPermissions,
  canPerformActionInternal,
  PERMISSION_DEFAULTS_BY_MODE,
} from "./lib/permissions";
export {
  defaultContentCardKebabActions,
  stripQuotedRecursion,
} from "./lib/defaults";

// ─── v0.3 — sub-exported parts (badge primitives + composites) ──────────────
// Per description §10 #7: 6 main composite parts + 5 small badge primitives.
// C5 ships the badge primitives + the badge-stack composite; C6 adds author/publisher;
// C7-C10 add paywall/sensitive/quoted/engagement.
export { NewsBadges } from "./parts/news-badges";
export { StatusBadge } from "./parts/status-badge";
export { VisibilityBadge } from "./parts/visibility-badge";
export { SponsorBadge } from "./parts/sponsor-badge";
export { LiveUpdateLine } from "./parts/live-update-line";
export { NewsAuthorByline } from "./parts/news-author-byline";
export { NewsPublisherRow } from "./parts/news-publisher-row";
export { NewsPaywallGate } from "./parts/news-paywall-gate";
export { ContentSensitiveGate } from "./parts/content-sensitive-gate";
export { QuotedArticleCard } from "./parts/quoted-article-card";
export { NewsEngagementCounts } from "./parts/news-engagement-counts";
export { NewsKebab } from "./parts/news-kebab";

import type { ElementType, MouseEvent, ReactNode, Ref } from "react";

// F-S1 lock: cross-procomp imports use RELATIVE paths to specific files
// (NOT barrels) so shadcn 4.6.0's path-rewriter doesn't mangle them.
// See .claude/decisions/2026-05-28-post-card-01-v0.3.1-fcross-11-fs1-cleanup.md
import type { CommentMenuItem } from "../comment-thread-01/types";

// ─────────────────────────────────────────────────────────────────────────────
// v0.2 surface (preserved unchanged — every v0.2.x consumer keeps working)
// ─────────────────────────────────────────────────────────────────────────────

export type ContentCardNewsVariant =
  | "featured"
  | "large"
  | "medium"
  | "small"
  | "list";

// ─────────────────────────────────────────────────────────────────────────────
// v0.3.0 — Role-aware mode
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Two-mode toggle for role-aware kebab + render affordances.
 *  - `"editor"`: shows Edit / Delete / Publish / Unpublish / Schedule / Feature /
 *    Pin / Change visibility / Change category / Mark sensitive / See analytics /
 *    Push to top kebab items (when their handlers are wired and the matrix permits).
 *  - `"viewer"`: shows Report / Block author / Mute author / Unfollow topic
 *    (when wired and the matrix permits).
 *
 * **Opt-in semantics (per Q-D1 lock):** `viewerMode === undefined` → v0.2 legacy
 * mode (NO kebab rendered unless any of the new role-aware args is explicitly
 * set). No auto-derivation from any identity source — the host explicitly picks
 * the mode to keep the library neutral across identity / role models.
 *
 * **Moderator UX** (take-down, feature, lock, etc.) is **NOT** a third value —
 * moderation is an orthogonal capability that crosses editor / viewer lines.
 * Wire it via `permissions.canModerate: true` (or
 * `canPerformAction("moderate", item) === true`) PLUS the
 * {@link ContentCardNewsProps.moderatorActions} slot which supplies the menu items.
 * The moderator section renders between common items and viewer-destructive
 * items with a divider above it. Full kebab takeover via
 * {@link ContentCardNewsProps.kebabActions} still bypasses everything.
 */
export type NewsViewerMode = "editor" | "viewer";

// ─────────────────────────────────────────────────────────────────────────────
// v0.3.0 — Status + Visibility
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Lifecycle status of an article. CLOSED enum per Q-P31 — library owns the
 * full set so it can render canonical badges. Hosts with custom workflow
 * states should encode via {@link NewsVisibility} (which IS extensible).
 *
 * Rendering: only `"draft"` / `"scheduled"` / `"archived"` render a badge.
 * `"published"` is the implicit baseline and produces no badge.
 *
 * Editor-only: status badge renders only when `viewerMode === "editor"` per
 * Q-D10 lock. Readers never see the status chip.
 */
export type ContentStatus =
  | "draft"
  | "scheduled"
  | "published"
  | "archived";

/**
 * Facebook-style extensible visibility/access-tier shape per Q-P30.
 *
 * Library renders default labels for the 5 base values via
 * `DEFAULT_LABELS`. Custom string values (e.g. `"gold-tier"`,
 * `"employees-only"`, `"newsletter-subscribers"`) get a fallback "Custom"
 * label. Granular host-specific tiers are encoded as their own string keys.
 *
 * - `"public"` — visible to everyone
 * - `"members"` — visible to logged-in members
 * - `"subscribers"` — visible to paying subscribers (paywall typically aligns to this tier)
 * - `"staff"` — visible to internal editorial / CMS users only
 * - `"unlisted"` — published but hidden from feeds / listings (URL access only)
 * - `(string & {})` — branded extension for host-specific tiers
 */
export type NewsVisibility =
  | "public"
  | "members"
  | "subscribers"
  | "staff"
  | "unlisted"
  | (string & {});

// ─────────────────────────────────────────────────────────────────────────────
// v0.3.0 — Entity sub-types
// ─────────────────────────────────────────────────────────────────────────────

export interface NewsArticleAuthor {
  id: string;
  name: string;
  /** Optional role label — "Senior Editor", "Contributor", "Wire Reporter". */
  role?: string;
  avatar?: string;
  isVerified?: boolean;
}

export interface NewsPublisher {
  id: string;
  name: string;
  logo?: string;
  slug?: string;
}

export interface ContentSensitivity {
  isSensitive: boolean;
  reason?: string;
  /** Specific content warnings — ["graphic", "death", "violence", "nudity"]. */
  contentWarnings?: string[];
}

/**
 * Premium-gate over excerpt + media (per Q-P33). Distinct from
 * {@link ContentSensitivity} (monetization vs content-warning motivation; see
 * description §3.2).
 */
export interface ContentPaywall {
  isPaywalled: boolean;
  /** Subscription tier required to access — matches a {@link NewsVisibility} value. */
  tier?: string;
  /** First N words shown above the gate (renders inline when set). */
  preview?: string;
  /** Custom label on the CTA button. Defaults to "Subscribe to read" via labels. */
  ctaLabel?: string;
  /**
   * When set, CTA renders as `<a href={ctaHref}>` (host can pass `linkComponent`
   * to swap to Next/Remix link). `onClick` fires `onRevealPaywall(articleId)`
   * BEFORE navigation as an analytics hook. When unset, CTA renders as
   * `<button>` and only fires `onRevealPaywall`.
   */
  ctaHref?: string;
}

// ─────────────────────────────────────────────────────────────────────────────
// v0.3.0 — Extended ContentCardItem (31 new optional fields)
// ─────────────────────────────────────────────────────────────────────────────

export interface ContentCardItem {
  // ─── v0.1 / v0.2 core (unchanged) ────────────────────────────────────────
  /** Stable identifier. Used for React keys and the default ariaLabel. */
  id: string;
  /** Headline. Rendered in the H-tag appropriate for the variant. */
  title: string;
  /** Image URL. */
  image: string;
  /** Short summary or lead paragraph. Variants gracefully omit when absent. */
  excerpt?: string;
  /** Category / tag string. Used as a key into `categoryStyles`. */
  category?: string;
  /**
   * Author byline as a plain string (legacy v0.1 shape). Stays for soft-compat.
   * When {@link ContentCardItem.authorEntity} is also set, the structured
   * version wins for rendering; this string is the fallback.
   */
  author?: string;
  /**
   * Publish date — ISO-8601 string or Date. Stays for soft-compat.
   * When {@link ContentCardItem.publishedAt} is set, it wins; this is the fallback.
   */
  date?: string | Date;
  /** Estimated read time in minutes. */
  readTime?: number;
  /** View count for engagement chip. Only `medium` renders this. */
  views?: number;

  // ─── v0.3.0 schema expansion (all optional; v0.2.x shape still satisfies) ─

  /** URL slug — canonical-URL composition, deep-linking. */
  slug?: string;

  /** Structured author — wins over the string `author` field when both set. */
  authorEntity?: NewsArticleAuthor;

  /** Publisher / source — wire-service / multi-source attribution. */
  publisher?: NewsPublisher;

  /** Canonical published timestamp — wins over `date` when both set. */
  publishedAt?: string | Date | number;
  /** Timestamp of the last edit. Renders an "(edited)" suffix on the date row. */
  updatedAt?: string | Date | number;
  /** Future timestamp when a `status: "scheduled"` article will publish. */
  scheduledFor?: string | Date | number;

  /** Lifecycle status. Only editor-mode renders the badge (Q-D10). */
  status?: ContentStatus;
  /** Audience / access tier. Renders a visibility badge in the badge stack. */
  visibility?: NewsVisibility;
  /** Topic taxonomy axis (separate from `category` / `tags`). */
  topics?: string[];
  /** Freeform hashtag-style chips. */
  tags?: string[];
  /** BCP-47 language tag. Drives `onTranslate` kebab item visibility. */
  language?: string;
  /** Languages this article is available in (data only in v0.3 — no render). */
  availableTranslations?: string[];

  /** Pinned articles render a "Pinned" badge. */
  isPinned?: boolean;
  /** Featured articles render a "Featured" badge. */
  isFeatured?: boolean;
  /** Breaking-news articles render a "Breaking" badge. Highest priority. */
  isBreaking?: boolean;
  /** Live-blog articles render a "Live" badge + optional live-update sub-line. */
  isLive?: boolean;
  /** Exclusive content renders an "Exclusive" badge. */
  isExclusive?: boolean;
  /** Sponsored content renders a "Sponsored" badge. */
  isSponsored?: boolean;
  /** Optional sponsor name — renders as "Sponsored by {name}" when set. */
  sponsorLabel?: string;

  /** Number of live updates posted (only meaningful when `isLive`). */
  liveUpdateCount?: number;
  /** Timestamp of the most-recent live update. */
  lastLiveUpdateAt?: string | Date | number;

  /** Sensitive-content gate (per-card). */
  sensitivity?: ContentSensitivity;
  /** Paywall gate (per-card). */
  paywall?: ContentPaywall;

  /** When false, comment-count chip is suppressed regardless of `commentCount`. */
  commentsEnabled?: boolean;
  /** Comment count for engagement chip. */
  commentCount?: number;
  /** Like count for engagement chip. */
  likeCount?: number;
  /** Whether the current viewer has liked this article. */
  isLiked?: boolean;
  /** Bookmark count for engagement chip. */
  bookmarkCount?: number;
  /** Whether the current viewer has bookmarked this article. */
  isBookmarked?: boolean;
  /** Share count for engagement chip. */
  shareCount?: number;

  /**
   * Quoted / referenced parent article — renders as a nested compact mini-card.
   * Recursion-strip applies: the inner card's own `quotedArticle` is ignored
   * (no infinite nesting). Per Q-P32 + Q-PE renders only in `medium` + `list`
   * variants.
   */
  quotedArticle?: ContentCardItem;
}

// ─────────────────────────────────────────────────────────────────────────────
// v0.3.0 — Permissions matrix
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Discriminator for the universal {@link ContentCardNewsProps.canPerformAction}
 * predicate. 19 actions spanning editor / host-policy / reader / moderator.
 */
export type ContentCardPermissionAction =
  // editor-side (12)
  | "edit"
  | "delete"
  | "publish"
  | "unpublish"
  | "schedule"
  | "feature"
  | "pin"
  | "changeVisibility"
  | "changeCategory"
  | "markSensitive"
  | "seeAnalytics"
  | "pushToTop"
  // host-policy gates (2)
  | "share"
  | "bookmark"
  // reader-side (4)
  | "report"
  | "blockAuthor"
  | "muteAuthor"
  | "unfollowTopic"
  // moderator (1)
  | "moderate";

/**
 * Per-action permissions matrix. Overrides the `viewerMode`-derived defaults.
 *
 * **Resolution order (most → least specific):**
 *  1. `canPerformAction(action, item)` returning `true` / `false` — wins everything
 *  2. `permissions[canX]` per-field — `false` denies, `true` allows
 *  3. `viewerMode`-derived defaults (`"editor"` → editor-side `true`, reader-side `false`; `"viewer"` → inverse)
 *  4. Library-baseline default (legacy mode — no `viewerMode` + no `permissions` + no `canPerformAction`): no kebab rendered
 *
 * `canShare` / `canBookmark` are **host-policy gates** — reader-side actions
 * whose visibility the host can deny (e.g. paywalled articles may hide Share
 * for non-subscribers).
 *
 * `canModerate` is **orthogonal** to editor / viewer modes. When `true` AND
 * {@link ContentCardNewsProps.moderatorActions} returns ≥1 item, the kebab
 * renders a moderator section between common items and reader-destructive
 * items with a divider above. Defaults to `false` in both viewer modes.
 */
export interface ContentCardPermissions {
  // editor-side (12)
  canEdit?: boolean;
  canDelete?: boolean;
  canPublish?: boolean;
  canUnpublish?: boolean;
  canSchedule?: boolean;
  canFeature?: boolean;
  canPin?: boolean;
  canChangeVisibility?: boolean;
  canChangeCategory?: boolean;
  canMarkSensitive?: boolean;
  canSeeAnalytics?: boolean;
  canPushToTop?: boolean;
  // host-policy gates (2)
  canShare?: boolean;
  canBookmark?: boolean;
  // reader-side (4)
  canReport?: boolean;
  canBlockAuthor?: boolean;
  canMuteAuthor?: boolean;
  canUnfollowTopic?: boolean;
  // moderator (1)
  canModerate?: boolean;
}

