    sensitiveRevealed,
    onRevealPaywallInternal,
    onRevealSensitiveInternal,
    renderBadges,
    renderAuthor,
    renderExcerpt,
    renderPaywallGate,
    renderSensitiveGate,
    renderEngagementCounts,
    disableBadgesRender,
    disableAuthorRender,
    disableExcerptRender,
    disablePaywallGate,
    disableSensitiveGate,
    disableEngagementCounts,
    engagementHandlers,
    kebabItems,
    onAuthorClick,
    onPublisherClick,
    onCategoryClick,
  } = props;

  const isEditorMode = viewerMode === "editor";
  const showKebab = kebabItems.length > 0;

  const mediaBlock = (
    <div className="relative h-64 overflow-hidden md:h-full md:min-h-75">
      <img
        src={item.image}
        alt={item.title}
        loading={loading}
