              className="relative z-10 mb-4 w-fit"
              aria-label={`Category: ${item.category}`}
            >
              <Badge className={cn(categoryStyle, "cursor-pointer")}>
                {item.category}
              </Badge>
            </button>
          ) : (
            <Badge
              className={cn(categoryStyle, "mb-4 w-fit")}
              aria-label={`Category: ${item.category}`}
            >
              {item.category}
            </Badge>
