          )
        ) : null}
        <h4
          id={titleId}
          className={cn(
            "text-sm font-semibold transition-colors line-clamp-2 motion-safe:group-hover:text-primary",
            titleClassName,
          )}
        >
          {item.title}
        </h4>
        {formattedRelativeTime ? (
          <span className="mt-1 text-xs text-muted-foreground">
            {formattedRelativeTime}
          </span>
        ) : null}
      </div>
    </article>
  );
}

import { ArrowRight } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { ResolvedPartProps } from "../types";
import { NewsBadges } from "./news-badges";
import { VisibilityBadge } from "./visibility-badge";
import { LiveUpdateLine } from "./live-update-line";
import { NewsAuthorByline } from "./news-author-byline";
import { NewsPaywallGate } from "./news-paywall-gate";
import { ContentSensitiveGate } from "./content-sensitive-gate";
import { QuotedArticleCard } from "./quoted-article-card";
import { NewsEngagementCounts } from "./news-engagement-counts";
import { NewsKebab } from "./news-kebab";

/**
 * List variant — full-width row, compact density. Author + chevron / actions / kebab right-aligned.
 *
 * v0.3 features per Q-PA matrix: full badge stack (inline), kebab (replaces chevron when items),
 * paywall + sensitive gates (over excerpt; list has no image), quoted article, engagement counts,
 * structured author byline. NO publisher logo / topic chips / tag chips per matrix.
 */
export function ListPart(props: ResolvedPartProps) {
  const {
    item,
    formattedRelativeTime,
    labels,
    LinkComponent,
    href,
    onClick,
    ariaLabel,
    titleId,
    titleClassName,
    className,
    actions,
    viewerMode,
    canModerate,
    paywallRevealed,
    sensitiveRevealed,
    onRevealPaywallInternal,
    onRevealSensitiveInternal,
    renderBadges,
    renderAuthor,
    renderExcerpt,
    renderPaywallGate,
    renderSensitiveGate,
    renderQuoted,
    renderEngagementCounts,
    disableBadgesRender,
    disableAuthorRender,
    disableExcerptRender,
    disablePaywallGate,
    disableSensitiveGate,
    disableQuotedRender,
    disableEngagementCounts,
    engagementHandlers,
    kebabItems,
    onAuthorClick,
    onCategoryClick,
    onQuotedClick,
  } = props;

  const isEditorMode = viewerMode === "editor";
  const showKebab = kebabItems.length > 0;

  // Paywall scope: list has no image, so the gate wraps the excerpt area
  // (Q-PG — gates excerpt + media; in list there's only excerpt).
  // Substitute paywall.preview for item.excerpt as the body text when
  // paywalled — title stays visible above, author/quoted/engagement below.
  const isPaywalled =
    !disablePaywallGate && Boolean(item.paywall?.isPaywalled) && !paywallRevealed;

  const previewText =
    isPaywalled && item.paywall?.preview
      ? `${item.paywall.preview} ${labels.paywallPreviewSeparator}`
      : null;
  const displayExcerpt = previewText ?? item.excerpt;

  const excerptBlock =
    !disableExcerptRender && displayExcerpt ? (
      renderExcerpt ? (
        renderExcerpt(item)
      ) : (
        <p className="mt-1 text-sm text-muted-foreground line-clamp-1">
          {displayExcerpt}
        </p>
      )
    ) : null;

  const sensitiveGatedExcerpt =
    !disableSensitiveGate && item.sensitivity?.isSensitive ? (
      renderSensitiveGate ? (
        renderSensitiveGate(item, { onReveal: onRevealSensitiveInternal })
      ) : (
        <ContentSensitiveGate
          sensitivity={item.sensitivity}
          revealed={sensitiveRevealed}
          onReveal={onRevealSensitiveInternal}
          labels={labels}
        >
          {excerptBlock}
        </ContentSensitiveGate>
      )
    ) : (
      excerptBlock
    );

  const gatedExcerpt = isPaywalled
    ? renderPaywallGate
      ? renderPaywallGate(item, { onReveal: onRevealPaywallInternal })
      : (
          <NewsPaywallGate
            paywall={item.paywall}
            revealed={paywallRevealed}
            onReveal={onRevealPaywallInternal}
            linkComponent={LinkComponent}
            labels={labels}
          >
            {sensitiveGatedExcerpt}
          </NewsPaywallGate>
        )
    : sensitiveGatedExcerpt;

  const innerContent = (
    <>
      {(item.category || formattedRelativeTime || !disableBadgesRender) && (
        <div className="mb-2 flex flex-wrap items-center gap-2">
          {!disableBadgesRender &&
            (renderBadges ? (
              renderBadges(item, { canModerate })
            ) : (
              <NewsBadges
                item={item}
                labels={labels}
                isEditorMode={isEditorMode}
              />
            ))}
          {item.category ? (
            onCategoryClick ? (
              <button
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  e.preventDefault();
                  onCategoryClick(item.category!);
                }}
                className="relative z-10"
                aria-label={`Category: ${item.category}`}
              >
                <Badge variant="outline" className="cursor-pointer text-xs">
                  {item.category}
                </Badge>
              </button>
            ) : (
              <Badge
                variant="outline"
                className="text-xs"
                aria-label={`Category: ${item.category}`}
              >
                {item.category}
              </Badge>
            )
          ) : null}
          <VisibilityBadge visibility={item.visibility} labels={labels} />
          {formattedRelativeTime ? (
            <span className="text-xs text-muted-foreground">
              {formattedRelativeTime}
            </span>
          ) : null}
          <LiveUpdateLine item={item} labels={labels} />
        </div>
      )}
      <h4
        id={titleId}
        className={cn(
          "font-semibold transition-colors line-clamp-1 motion-safe:group-hover:text-primary",
          titleClassName,
        )}
      >
        {item.title}
      </h4>
      {gatedExcerpt}

      {!disableAuthorRender && item.authorEntity ? (
        renderAuthor ? (
          renderAuthor(item.authorEntity, { publisher: item.publisher })
        ) : (
          <NewsAuthorByline
            author={item.authorEntity}
            onAuthorClick={onAuthorClick}
            labels={labels}
            className="mt-1"
          />
        )
      ) : null}

      {!disableQuotedRender && item.quotedArticle ? (
        renderQuoted ? (
          renderQuoted(item, {
            onClick: onQuotedClick
              ? () => onQuotedClick(item.quotedArticle!)
              : undefined,
          })
        ) : (
          <div className="mt-2">
            <QuotedArticleCard
              quotedArticle={item.quotedArticle}
              onClick={onQuotedClick}
              labels={undefined}
            />
          </div>
        )
      ) : null}

      {!disableEngagementCounts ? (
        renderEngagementCounts ? (
          <div className="relative z-10 mt-2">
            {renderEngagementCounts(item, {
              handlers: {
                onLike: engagementHandlers.onLike
                  ? (id, nextLiked) => engagementHandlers.onLike?.(nextLiked)
                  : undefined,
                onComment: engagementHandlers.onComment
                  ? () => engagementHandlers.onComment?.()
                  : undefined,
                onShare: engagementHandlers.onShare
                  ? () => engagementHandlers.onShare?.()
                  : undefined,
                onBookmark: engagementHandlers.onBookmark
                  ? (id, nextBookmarked) =>
                      engagementHandlers.onBookmark?.(nextBookmarked)
                  : undefined,
              },
            })}
          </div>
        ) : (
          <NewsEngagementCounts
            item={item}
            handlers={engagementHandlers}
            labels={labels}
            className="mt-2"
          />
        )
      ) : null}
    </>
  );

  return (
    <article
      className={cn(
        "group relative flex gap-4 rounded-lg border-b border-border/50 px-2 py-4 transition-colors last:border-0 hover:bg-muted/30",
        "has-[a:focus-visible]:ring-2 has-[a:focus-visible]:ring-ring has-[a:focus-visible]:ring-offset-2",
        className,
      )}
    >
      {href ? (
        <LinkComponent
          href={href}
          aria-labelledby={titleId}
          aria-label={ariaLabel}
          onClick={onClick}
          className="absolute inset-0 z-0 rounded-lg outline-none"
        />
      ) : null}

      <div className="min-w-0 flex-1">{innerContent}</div>

      <div className="flex shrink-0 items-center gap-1 self-center">
        {actions ? (
          <div className="relative z-10">{actions}</div>
        ) : null}
        {showKebab ? (
          <NewsKebab items={kebabItems} />
        ) : !actions ? (
          <ArrowRight
            aria-hidden="true"
            className="h-4 w-4 text-muted-foreground transition-all motion-safe:group-hover:translate-x-1 motion-safe:group-hover:text-primary rtl:rotate-180"
          />
        ) : null}
      </div>
    </article>
  );
}

import { AlertTriangle, Pin, Star, ShieldCheck } from "lucide-react";
import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import type { ContentCardItem, ContentCardNewsLabels } from "../types";
import { StatusBadge } from "./status-badge";
import { SponsorBadge } from "./sponsor-badge";

/**
 * Two logical groups inside the badge stack — they're conceptually different
 * and editorial design wants them in different positions on the card:
 *
 *   - `"state"` — Breaking / Live / Pinned / Sponsored / Status: WHAT IS THE
 *     STATE of this content (urgency / admin / commercial disclosure).
 *     Belongs on the IMAGE overlay (top-right corner in medium / large; top
 *     of the hero in featured) — they answer "should I look at this now?".
 *
 *   - `"curation"` — Exclusive / Featured: WHAT KIND OF EDITORIAL PRODUCT
 *     is this (Exclusive scoop / Featured pick). Belongs as a KICKER above
 *     the title in the body — they answer "what kind of journalism is this?".
 *
 * The priority order from Q-P42 is preserved within each group; the split
 * is purely visual layout (not a re-prioritization).
 */
export type NewsBadgeGroup = "all" | "state" | "curation";

interface NewsBadgesProps {
  item: ContentCardItem;
  labels: Required<ContentCardNewsLabels>;
  /**
   * When `true`, only the highest-priority badge renders. Used by the `small`
   * variant per Q-PA matrix. Operates AFTER the group filter when both are set.
   */
  highestPriorityOnly?: boolean;
  /**
   * Whether the viewer is in editor mode — status badge only renders then.
   */
  isEditorMode?: boolean;
  /**
   * Which logical group to render. Default `"all"`. See {@link NewsBadgeGroup}
   * for the split rationale.
   */
  group?: NewsBadgeGroup;
  className?: string;
}

/**
 * Uniform editorial badge — same shape + sizing across all states (h-5,
 * px-2, py-0, text-[10px], font-semibold, uppercase, tracking-wide). Visual
 * hierarchy lives in saturation: vivid solid for breaking-tier (Breaking /
 * Live); accent solid for editorial-curation (Featured / Exclusive); subtle
 * card-tone for low-tier (Pinned / Sponsored / status). No border-tint mix.
 * Drop-shadow on the vivid tier so they read against bright hero images.
 *
 * Sized for ~5 badges to fit on a single line at medium-card width (~280px)
 * without wrapping. Beyond that, flex-wrap kicks in.
 */
const BADGE_BASE =
  "inline-flex h-5 shrink-0 items-center gap-1 rounded px-1.5 text-[10px] font-semibold uppercase tracking-wide leading-none";

/**
 * Ordered editorial badge stack per Q-P42 priority:
 *  1. isBreaking
 *  2. isLive
 *  3. isExclusive
 *  4. isFeatured
 *  5. isPinned
 *  6. isSponsored
 *  7. status (editor mode only; renders nothing for `published`)
 *
 * `small` variant passes `highestPriorityOnly` to limit to the top badge.
 * RSC-compatible.
 */
export function NewsBadges({
  item,
  labels,
  highestPriorityOnly = false,
  isEditorMode = false,
  group = "all",
  className,
}: NewsBadgesProps) {
  const candidates: ReactNode[] = [];

  // ─── State-group candidates ────────────────────────────────────────────
  const wantsState = group === "all" || group === "state";

  if (wantsState && item.isBreaking) {
    candidates.push(
      <span
        key="breaking"
        className={cn(
          BADGE_BASE,
          "bg-red-600 text-white shadow-sm shadow-red-950/30 ring-1 ring-red-700/40",
        )}
      >
        <AlertTriangle className="size-2.5" aria-hidden />
        {labels.breakingBadgeLabel}
      </span>,
    );
  }
  if (wantsState && item.isLive) {
    candidates.push(
      <span
        key="live"
        className={cn(
          BADGE_BASE,
          "bg-red-500 text-white shadow-sm shadow-red-950/30 ring-1 ring-red-700/40",
        )}
      >
        <span
          className="relative inline-flex size-1.5 rounded-full bg-white motion-safe:animate-pulse"
          aria-hidden
        />
        {labels.liveBadgeLabel}
      </span>,
    );
  }

  // ─── Curation-group candidates ─────────────────────────────────────────
  const wantsCuration = group === "all" || group === "curation";

  if (wantsCuration && item.isExclusive) {
    candidates.push(
      <span
        key="exclusive"
        className={cn(
          BADGE_BASE,
          "bg-amber-500 text-amber-950 shadow-sm shadow-amber-950/20",
        )}
      >
        <ShieldCheck className="size-2.5" aria-hidden />
        {labels.exclusiveBadgeLabel}
      </span>,
    );
  }
  if (wantsCuration && item.isFeatured) {
    candidates.push(
      <span
        key="featured"
        className={cn(
          BADGE_BASE,
          "bg-primary text-primary-foreground shadow-sm shadow-primary/20",
        )}
      >
        <Star className="size-2.5 fill-current" aria-hidden />
        {labels.featuredBadgeLabel}
      </span>,
    );
  }

  // ─── State-group continuation (Pinned / Sponsored / Status) ────────────
  if (wantsState && item.isPinned) {
    candidates.push(
      <span
        key="pinned"
        className={cn(BADGE_BASE, "bg-card/95 text-foreground ring-1 ring-border")}
      >
        <Pin className="size-2.5 fill-current" aria-hidden />
        {labels.pinnedBadgeLabel}
      </span>,
    );
  }
  if (wantsState && item.isSponsored) {
    candidates.push(
      <SponsorBadge
        key="sponsored"
        isSponsored={item.isSponsored}
        sponsorLabel={item.sponsorLabel}
        labels={labels}
      />,
    );
  }
  if (
    wantsState &&
    isEditorMode &&
    item.status &&
    item.status !== "published"
  ) {
    candidates.push(
      <StatusBadge key="status" status={item.status} labels={labels} />,
    );
  }

  if (candidates.length === 0) return null;

  const visible = highestPriorityOnly ? candidates.slice(0, 1) : candidates;

  return (
    <div className={cn("flex flex-wrap items-center gap-1", className)}>
      {visible}
    </div>
  );
}

import { FileEdit, CalendarClock, Archive } from "lucide-react";
import { cn } from "@/lib/utils";
import type { ContentStatus, ContentCardNewsLabels } from "../types";

interface StatusBadgeProps {
  status: ContentStatus | undefined;
  labels: Required<ContentCardNewsLabels>;
  className?: string;
}

/**
 * Status badge — editor-mode-only. Renders nothing for `"published"` (the
 * implicit baseline) or when `status` is undefined.
 *
 * RSC-compatible (no `"use client"`); pure presentation.
 */
export function StatusBadge({ status, labels, className }: StatusBadgeProps) {
  if (!status || status === "published") return null;

  const config = (() => {
    switch (status) {
      case "draft":
        return {
          label: labels.statusDraft,
          Icon: FileEdit,
          tone: "bg-muted text-muted-foreground ring-border",
        };
      case "scheduled":
        return {
          label: labels.statusScheduled,
          Icon: CalendarClock,
          tone: "bg-amber-500 text-amber-950 ring-amber-700/40",
        };
      case "archived":
        return {
          label: labels.statusArchived,
          Icon: Archive,
          tone: "bg-secondary text-secondary-foreground ring-border",
        };
    }
  })();

  if (!config) return null;
  const { label, Icon, tone } = config;

  return (
    <span
      className={cn(
        "inline-flex h-5 shrink-0 items-center gap-1 rounded px-1.5 text-[10px] font-semibold uppercase tracking-wide leading-none ring-1",
        tone,
        className,
      )}
    >
      <Icon className="size-2.5" aria-hidden />
      {label}
    </span>
  );
}

import { Globe, Users, BadgeCheck, Shield, EyeOff } from "lucide-react";
import { cn } from "@/lib/utils";
import type { NewsVisibility, ContentCardNewsLabels } from "../types";

interface VisibilityBadgeProps {
  visibility: NewsVisibility | undefined;
  labels: Required<ContentCardNewsLabels>;
  className?: string;
}

/**
 * Visibility / access-tier badge. Renders for any visibility value EXCEPT
 * `"public"` (the implicit default — no badge for free, public content)
 * and `undefined`.
 *
 * RSC-compatible.
 */
export function VisibilityBadge({
  visibility,
  labels,
  className,
}: VisibilityBadgeProps) {
  if (!visibility || visibility === "public") return null;

  const { label, Icon } = (() => {
    switch (visibility) {
      case "members":
        return { label: labels.visibilityMembers, Icon: Users };
      case "subscribers":
        return { label: labels.visibilitySubscribers, Icon: BadgeCheck };
      case "staff":
        return { label: labels.visibilityStaff, Icon: Shield };
      case "unlisted":
        return { label: labels.visibilityUnlisted, Icon: EyeOff };
      default:
        // Branded extension — custom string value
        return { label: labels.visibilityCustom, Icon: Globe };
    }
  })();

  return (
    <span
      className={cn(
        "inline-flex items-center gap-1 rounded-md border border-border bg-card/60 px-1.5 py-0.5 text-[10px] font-medium",
        className,
      )}
      title={label}
    >
      <Icon className="size-3" aria-hidden />
      {label}
    </span>
  );
}

import { Megaphone } from "lucide-react";
import { cn } from "@/lib/utils";
import type { ContentCardNewsLabels } from "../types";

interface SponsorBadgeProps {
  /** Whether the item is sponsored. */
  isSponsored: boolean | undefined;
  /** Sponsor name — renders as "Sponsored by {name}" via template. */
  sponsorLabel: string | undefined;
  labels: Required<ContentCardNewsLabels>;
  className?: string;
}

/**
 * Sponsor badge — renders "Sponsored by {name}" when `sponsorLabel` is set,
 * otherwise "Sponsored". No render when `isSponsored !== true`.
 *
 * RSC-compatible.
 */
export function SponsorBadge({
  isSponsored,
  sponsorLabel,
  labels,
  className,
}: SponsorBadgeProps) {
  if (!isSponsored) return null;

  const text = sponsorLabel
    ? labels.sponsoredBadgeLabelTemplate.replace("{name}", sponsorLabel)
    : labels.sponsoredBadgeFallback;

  return (
    <span
      className={cn(
        "inline-flex h-5 shrink-0 items-center gap-1 rounded bg-card/95 px-1.5 text-[10px] font-semibold uppercase tracking-wide leading-none text-muted-foreground ring-1 ring-border",
        className,
      )}
    >
      <Megaphone className="size-2.5" aria-hidden />
      {text}
    </span>
  );
}

import { Radio } from "lucide-react";
import { cn } from "@/lib/utils";
import { defaultRelativeTime } from "../hooks/use-relative-time";
import { toDate } from "../lib/format-default";
import type { ContentCardItem, ContentCardNewsLabels } from "../types";

interface LiveUpdateLineProps {
  item: ContentCardItem;
  labels: Required<ContentCardNewsLabels>;
  /** Optional custom relative-time formatter (root passes its resolved one). */
  formatRelativeTime?: (date: Date, now?: Date) => string;
  className?: string;
}

/**
 * Live-update sub-line — rendered below the date when `isLive === true` AND
 * `lastLiveUpdateAt` is set. Renders "Updated 3m ago · 14 updates" using the
 * `liveUpdatedTemplate` label (placeholders `{time}` + `{count}`).
 *
 * Visual: small pulsing dot prefix for the live signal. `motion-reduce`
 * removes the pulse.
 *
 * RSC-compatible.
 */
export function LiveUpdateLine({
  item,
  labels,
  formatRelativeTime,
  className,
}: LiveUpdateLineProps) {
  if (!item.isLive || !item.lastLiveUpdateAt) return null;

  const date = toDate(item.lastLiveUpdateAt);
  if (!date) return null;

  const time = (formatRelativeTime ?? defaultRelativeTime)(date);
  const count = item.liveUpdateCount ?? 0;
  const text = labels.liveUpdatedTemplate
    .replace("{time}", time)
    .replace("{count}", String(count));

  return (
    <span
      className={cn(
        "inline-flex items-center gap-1.5 text-[11px] font-medium text-muted-foreground",
        className,
      )}
    >
      <span
        className="relative inline-flex size-2 rounded-full bg-red-500 motion-safe:animate-pulse"
        aria-hidden
      />
      <Radio className="size-3" aria-hidden />
      {text}
    </span>
  );
}

import { BadgeCheck } from "lucide-react";
import type { ElementType, MouseEvent } from "react";
import { cn } from "@/lib/utils";
import type {
  ContentCardNewsLabels,
  NewsArticleAuthor,
  NewsPublisher,
} from "../types";

interface NewsAuthorBylineProps {
  /**
   * Structured author OR plain string (v0.2 soft-compat). When both an
   * `authorEntity` and `author` string are on the item, the root component
   * passes the structured one and this part renders it; otherwise the string
   * fallback path is taken.
   */
  author: NewsArticleAuthor | string | undefined;
  /** Publisher to render in a small sub-line below the author. */
  publisher?: NewsPublisher | undefined;
  /** Optional click handler — wraps the byline in a button when set. */
  onAuthorClick?: (author: NewsArticleAuthor) => void;
  /** Optional publisher click handler. */
  onPublisherClick?: (publisher: NewsPublisher) => void;
  /** Optional polymorphic element for author link (when an id-bearing author is clickable). */
  authorComponent?: ElementType;
  labels: Required<ContentCardNewsLabels>;
  className?: string;
}

/**
 * Author byline cluster.
 *
 * - Structured author: avatar (when set) + name + optional role + verified tick
 * - String fallback: just the name (no avatar, no role)
 * - Publisher (optional): rendered on a second line below the author
 *
 * RSC-compatible — no DOM state. Click handlers fire on the rendered button
 * elements which are hydrated by the consumer's React runtime.
 */
export function NewsAuthorByline({
  author,
  publisher,
  onAuthorClick,
  onPublisherClick,
  authorComponent: AuthorComponent = "button",
  labels,
  className,
}: NewsAuthorBylineProps) {
  if (!author && !publisher) return null;

  const structured = isStructuredAuthor(author) ? author : undefined;
  const nameText = structured?.name ?? (typeof author === "string" ? author : undefined);

  const handleAuthorClick = (event: MouseEvent) => {
    if (!structured || !onAuthorClick) return;
    event.preventDefault();
    onAuthorClick(structured);
  };

  const handlePublisherClick = (event: MouseEvent) => {
    if (!publisher || !onPublisherClick) return;
    event.preventDefault();
    onPublisherClick(publisher);
  };

  return (
    <div
      className={cn(
        "flex flex-col gap-0.5 text-xs text-muted-foreground",
        className,
      )}
    >
      {nameText && (
        <div className="flex items-center gap-1.5">
          {structured?.avatar && (
            <img
              src={structured.avatar}
              alt=""
              aria-hidden
              className="size-5 rounded-full object-cover"
            />
          )}
          {structured && onAuthorClick ? (
            <AuthorComponent
              type={AuthorComponent === "button" ? "button" : undefined}
              onClick={handleAuthorClick}
              className="relative z-10 -mx-1 cursor-pointer rounded-sm px-1 font-medium text-foreground transition-colors hover:text-primary focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            >
              {nameText}
            </AuthorComponent>
          ) : (
            <span className="font-medium text-foreground">{nameText}</span>
          )}
          {structured?.isVerified && (
            <BadgeCheck
              className="size-3.5 text-primary"
              aria-label={labels.verifiedAuthorLabel}
            />
          )}
          {structured?.role && (
            <span className="text-muted-foreground/80">· {structured.role}</span>
          )}
        </div>
      )}
      {publisher && (
        <div className="flex items-center gap-1.5">
          {publisher.logo && (
            <img
              src={publisher.logo}
              alt=""
              aria-hidden
              className="size-4 rounded object-contain"
            />
          )}
          {onPublisherClick ? (
            <button
              type="button"
              onClick={handlePublisherClick}
              className="relative z-10 -mx-1 cursor-pointer rounded-sm px-1 transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            >
              {publisher.name}
            </button>
          ) : (
            <span>{publisher.name}</span>
          )}
        </div>
      )}
    </div>
  );
}

function isStructuredAuthor(
  value: NewsArticleAuthor | string | undefined,
): value is NewsArticleAuthor {
  return typeof value === "object" && value !== null && "id" in value && "name" in value;
}

import type { MouseEvent } from "react";
import { cn } from "@/lib/utils";
import type { NewsPublisher } from "../types";

interface NewsPublisherRowProps {
  publisher: NewsPublisher | undefined;
  onPublisherClick?: (publisher: NewsPublisher) => void;
  /** When `true`, renders just the logo (no name). For tight variant slots. */
  logoOnly?: boolean;
  className?: string;
}

/**
 * Standalone publisher row — logo + name + optional click handler.
 *
 * Use case beyond the author byline: featured/large variants render this
 * inline above the title as the "source attribution" chip (parallels the
 * `featured`-variant category chip pattern).
 *
 * RSC-compatible — no DOM state.
 */
export function NewsPublisherRow({
  publisher,
  onPublisherClick,
  logoOnly = false,
  className,
}: NewsPublisherRowProps) {
  if (!publisher) return null;

  const handleClick = (event: MouseEvent) => {
    if (!onPublisherClick) return;
    event.preventDefault();
    onPublisherClick(publisher);
  };

  const content = (
    <>
      {publisher.logo && (
        <img
          src={publisher.logo}
          alt={logoOnly ? publisher.name : ""}
          aria-hidden={!logoOnly}
          className="size-5 rounded object-contain"
        />
      )}
      {!logoOnly && (
        <span className="text-xs font-medium">{publisher.name}</span>
      )}
    </>
  );

  const baseClass =
    "inline-flex items-center gap-1.5 rounded-md border border-border/60 bg-card/80 px-2 py-1 backdrop-blur-sm";

  if (onPublisherClick) {
    return (
      <button
        type="button"
        onClick={handleClick}
        className={cn(
          baseClass,
          "relative z-10 cursor-pointer transition-colors hover:bg-card focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
          className,
        )}
      >
        {content}
      </button>
    );
  }

  return <span className={cn(baseClass, className)}>{content}</span>;
}

