import { AlertOctagon, Eye } from "lucide-react";
import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import type {
  ContentCardNewsLabels,
  ContentSensitivity,
} from "../types";

interface ContentSensitiveGateProps {
  sensitivity: ContentSensitivity | undefined;
  /** Has the host pushed `sensitiveRevealed=true` via the handle's revealSensitive? */
  revealed?: boolean;
  /**
   * Internal reveal handler — fires `onRevealSensitive(articleId)` analytics
   * hook AND flips local `sensitiveRevealed` state.
   */
  onReveal: () => void;
  /**
   * The media this gate wraps. Renders normally when not sensitive, OR when
   * already revealed; otherwise is masked behind the blur overlay.
   */
  children: ReactNode;
  labels: Required<ContentCardNewsLabels>;
  /**
   * Compact rendering for tight containers (used by the `small` variant's
   * 96×96 thumb per Q-PA matrix). Drops the heading + warnings list +
   * 44px reveal button in favor of a single icon + tiny `<button>` pill
   * sized to fit a 96×96 container. The full overlay is too tall to fit a
   * sidebar-density thumb (~180px content height vs 96px container) — fall
   * back to compact when wrapping anything narrower than ~160×160.
   */
  compact?: boolean;
  className?: string;
}

/**
 * Sensitive content gate — content-warning overlay over media only.
 *
 * Distinct from `NewsPaywallGate` per Q-D9 — sensitive = content warning
 * (NSFW / graphic / upsetting); paywall = monetization gate. Different
 * motivations, different CTAs, separately styleable.
 *
 * UX: heavy blur over the media + an `AlertOctagon` icon + heading +
 * optional content-warning list + reveal button. Tap the button to reveal
 * for this session (state lives in the root component's `sensitiveRevealed`
 * mirror; the host can re-gate via `ref.current.reset(item)`).
 *
 * `prefers-reduced-motion` snaps reveal instead of fading.
 *
 * Sub-exported as `ContentSensitiveGate` for standalone use.
 */
export function ContentSensitiveGate({
  sensitivity,
  revealed = false,
  onReveal,
  children,
  labels,
  compact = false,
  className,
}: ContentSensitiveGateProps) {
  if (!sensitivity?.isSensitive || revealed) return <>{children}</>;

  const warnings = sensitivity.contentWarnings ?? [];
  const warningText = warnings.length
    ? labels.sensitiveContentWarningTemplate.replace(
        "{warnings}",
        warnings.join(", "),
      )
    : sensitivity.reason;

  return (
    <div className={cn("relative", className)}>
      <div
        className="motion-safe:transition-[filter,opacity] pointer-events-none select-none blur-xl opacity-30"
        aria-hidden
      >
        {children}
      </div>

      {compact ? (
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-1.5 rounded-md bg-card/95 p-2 text-center backdrop-blur-md">
          <AlertOctagon
            className="size-5 text-amber-600 dark:text-amber-400"
            aria-hidden
          />
          <button
            type="button"
            onClick={onReveal}
            aria-label={`${labels.sensitiveHeading}: ${labels.sensitiveRevealLabel}`}
            className="relative z-20 inline-flex cursor-pointer items-center gap-1 rounded-full bg-foreground/90 px-2 py-1 text-[11px] font-medium text-background transition-colors hover:bg-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1"
          >
            <Eye className="size-3" aria-hidden />
            {labels.sensitiveRevealLabel}
          </button>
        </div>
      ) : (
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-2 rounded-md bg-card/90 p-4 text-center backdrop-blur-md">
          <AlertOctagon
            className="size-6 text-amber-600 dark:text-amber-400"
            aria-hidden
          />
          <p className="text-sm font-semibold">{labels.sensitiveHeading}</p>
          {warningText && (
            <p className="text-xs text-muted-foreground">{warningText}</p>
          )}
          <button
            type="button"
            onClick={onReveal}
            className="relative z-20 mt-1 inline-flex h-11 cursor-pointer items-center justify-center gap-1.5 rounded-md border border-border bg-background px-4 text-sm font-medium transition-colors hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
          >
            <Eye className="size-4" aria-hidden />
            {labels.sensitiveRevealLabel}
          </button>
        </div>
      )}
    </div>
  );
}

"use client";

import { useMemo, type ElementType, type MouseEvent } from "react";
import { Quote } from "lucide-react";
import { cn } from "@/lib/utils";
import { ContentCardNews01 } from "../content-card-news-01";
import { stripQuotedRecursion } from "../lib/defaults";
import type { ContentCardItem, ContentCardNewsProps } from "../types";

export interface QuotedArticleCardProps {
  /** The original article being quoted. */
  quotedArticle: ContentCardItem;
  /**
   * Click handler — overrides default `href`-based navigation. When set,
   * the foreground click target renders as `<button>` and fires with the
   * quoted article. When omitted and `href` is set, renders as `<a href>`.
   * When neither set, the card is non-interactive (visual quote only).
   */
  onClick?: (quotedArticle: ContentCardItem) => void;
  /** Optional href for the default navigation case. */
  href?: string;
  /** Polymorphic root for the anchor case. Default 'a'. */
  linkComponent?: ContentCardNewsProps["linkComponent"];
  /** Forwarded to the nested `<ContentCardNews01>` for label strings. */
  labels?: ContentCardNewsProps["labels"];
  className?: string;
}

/**
 * Quoted article mini-card per Q-P32 + Q-PE.
 *
 * Renders a nested `<ContentCardNews01 variant="small">` with the compact
 * horizontal thumb-left, body-right layout. The small variant is the right
 * shape for a quote preview — full medium card recursion produced too much
 * vertical stack (own image header + own paywall + own author cluster) and
 * masked the parent card's own content.
 *
 * Defenses applied to the inner card:
 *  - `quotedArticle` stripped via {@link stripQuotedRecursion} (no infinite nesting)
 *  - `actions` undefined (no nested kebab; pointer-events-none wrapper blocks any leak)
 *  - `viewerMode` undefined (no role-aware UI in the nested card)
 *  - `disableQuotedRender` true (defense in depth — if recursion-strip ever drifts)
 *  - `disableEngagementCounts` true (no engagement on quoted articles)
 *  - `disablePaywallGate` true — quoted articles surface their TITLE + IMAGE
 *    for context. The paywall is a property of THIS reader's relationship to
 *    the quoted article, not relevant when previewing the quote attribution.
 *  - `disableSensitiveGate` true — same rationale (the quote preview is a
 *    citation, not the actual sensitive content; warning gates again would
 *    just hide what the reader needs to recognize the source).
 *  - `disableBadgesRender` true — initially we kept badges so quoted
 *    articles could surface their contextual state (Breaking / Live /
 *    Exclusive), but the small variant's top-right badge position
 *    overlapped the title in the compact preview. The quote should be a
 *    clean citation — if the host needs to indicate the quoted article's
 *    state, they render their own badge on the QuotedArticleCard wrapper
 *    via `className`. (v0.3 follow-up — reconsider if a quote variant
 *    with badge-on-thumb-corner lands later.)
 *
 * Inner article's own border / bg / padding flattened via `className` so the
 * QuotedArticleCard wrapper's `bg-muted/40 border border-border` styling is
 * the only "card chrome" — no double-frames.
 *
 * The inner card is wrapped in `pointer-events-none` so any descendant
 * interactivity cannot conflict with the foreground click target at `z-10`.
 *
 * Per the Q-PA matrix, this part renders only in `medium` + `list` variants —
 * the integration at C11 enforces that.
 */
export function QuotedArticleCard({
  quotedArticle,
  onClick,
  href,
  linkComponent: LinkComponent = "a" as ElementType,
  labels,
  className,
}: QuotedArticleCardProps) {
  const strippedItem = useMemo(
    () => stripQuotedRecursion(quotedArticle),
    [quotedArticle],
  );

  const handleClick = (event: MouseEvent) => {
    if (!onClick) return;
    event.preventDefault();
    onClick(quotedArticle);
  };

  const isInteractive = Boolean(onClick) || Boolean(href);

  return (
    <div
      className={cn(
        "relative rounded-md border border-border bg-muted/40",
        className,
      )}
    >
      {/* Quote glyph — top-right context cue */}
      <Quote
        className="pointer-events-none absolute right-2 top-2 z-[1] size-4 text-muted-foreground/50"
        aria-hidden
      />

      {/* Nested card — pointer-events-none stops nested interactives competing
          with the foreground click target below. Inner card's chrome flattened. */}
      <div className="pointer-events-none">
        <ContentCardNews01
          item={strippedItem}
          variant="small"
          labels={labels}
          actions={undefined}
          viewerMode={undefined}
          disableQuotedRender
          disableEngagementCounts
          disablePaywallGate
          disableSensitiveGate
          disableBadgesRender
          className="border-0 bg-transparent p-3 rounded-md shadow-none hover:shadow-none transition-none"
        />
      </div>

      {/* Foreground click target (when interactive) */}
      {isInteractive && (
        <>
          {onClick ? (
            <button
              type="button"
              onClick={handleClick}
              aria-label={`Read quoted article: ${quotedArticle.title}`}
              className="absolute inset-0 z-10 cursor-pointer rounded-md transition-colors hover:bg-foreground/5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            />
          ) : (
            <LinkComponent
              href={href}
              aria-label={`Read quoted article: ${quotedArticle.title}`}
              className="absolute inset-0 z-10 cursor-pointer rounded-md transition-colors hover:bg-foreground/5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            />
          )}
        </>
      )}
    </div>
  );
}

"use client";

import { Heart, MessageCircle, Bookmark, Share2 } from "lucide-react";
import { cn } from "@/lib/utils";
import type {
  ContentCardItem,
  ContentCardNewsLabels,
} from "../types";

interface EngagementHandlerBag {
  onLike?: (nextLiked: boolean) => void;
  onComment?: () => void;
  onShare?: () => void;
  onBookmark?: (nextBookmarked: boolean) => void;
}

interface NewsEngagementCountsProps {
  item: ContentCardItem;
  handlers: EngagementHandlerBag;
  labels: Required<ContentCardNewsLabels>;
  className?: string;
}

/**
 * Light engagement-counts row per Q-D6=(a) + Q-P35.
 *
 * Renders inline count chips for like / comment / bookmark / share. Each
 * chip:
 *   - Hides when count is missing AND its handler is missing (no data to show + no action to take)
 *   - Shows as a non-interactive count when count present but handler missing
 *   - Shows as an interactive button when handler present (count optional)
 *   - Suppresses comment chip when `item.commentsEnabled === false`
 *
 * The like chip has bistate styling — filled heart when `isLiked` true.
 * Bookmark chip same pattern.
 *
 * **Consumers wanting the full engagement-bar-01** (inline likers, share menu,
 * realtime subscribe) pass `<EngagementBar01>` into the
 * `renderEngagementCounts` slot — this part is the *default* render, swapped
 * out per the slot pattern per description §6.2. Engagement data shape on
 * `ContentCardItem` deliberately matches engagement-bar-01's counts shape so
 * the slot is drop-in.
 *
 * Sub-exported as `NewsEngagementCounts`.
 */
export function NewsEngagementCounts({
  item,
  handlers,
  labels,
  className,
}: NewsEngagementCountsProps) {
  const hasLike = Number.isFinite(item.likeCount) || Boolean(handlers.onLike);
  const hasComment =
    item.commentsEnabled !== false &&
    (Number.isFinite(item.commentCount) || Boolean(handlers.onComment));
  const hasBookmark =
    Number.isFinite(item.bookmarkCount) || Boolean(handlers.onBookmark);
  const hasShare = Number.isFinite(item.shareCount) || Boolean(handlers.onShare);

  if (!hasLike && !hasComment && !hasBookmark && !hasShare) return null;

  const formatCount = (n: number | undefined): string => {
    if (n === undefined) return "";
    if (n < 1000) return String(n);
    if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
    return `${(n / 1_000_000).toFixed(1)}m`;
  };

  return (
    <div
      className={cn(
        "relative z-10 flex flex-wrap items-center gap-1",
        className,
      )}
    >
      {hasLike && (
        <EngagementChip
          interactive={Boolean(handlers.onLike)}
          onClick={() => handlers.onLike?.(!item.isLiked)}
          ariaLabel={labels.likeAriaLabel.replace(
            "{count}",
            String(item.likeCount ?? 0),
          )}
          active={item.isLiked}
          activeTone="text-red-600 dark:text-red-400"
        >
          <Heart
            className={cn(
              "size-3.5",
              item.isLiked ? "fill-current" : "",
            )}
            aria-hidden
          />
          {item.likeCount !== undefined && (
            <span className="text-xs font-medium">
              {formatCount(item.likeCount)}
            </span>
          )}
        </EngagementChip>
      )}

      {hasComment && (
        <EngagementChip
          interactive={Boolean(handlers.onComment)}
          onClick={() => handlers.onComment?.()}
          ariaLabel={labels.commentAriaLabel.replace(
            "{count}",
            String(item.commentCount ?? 0),
          )}
        >
          <MessageCircle className="size-3.5" aria-hidden />
          {item.commentCount !== undefined && (
            <span className="text-xs font-medium">
              {formatCount(item.commentCount)}
            </span>
          )}
        </EngagementChip>
      )}

      {hasBookmark && (
        <EngagementChip
          interactive={Boolean(handlers.onBookmark)}
          onClick={() => handlers.onBookmark?.(!item.isBookmarked)}
          ariaLabel={labels.bookmarkAriaLabel.replace(
            "{count}",
            String(item.bookmarkCount ?? 0),
          )}
          active={item.isBookmarked}
          activeTone="text-primary"
        >
          <Bookmark
            className={cn(
              "size-3.5",
              item.isBookmarked ? "fill-current" : "",
            )}
            aria-hidden
          />
          {item.bookmarkCount !== undefined && (
            <span className="text-xs font-medium">
              {formatCount(item.bookmarkCount)}
            </span>
          )}
        </EngagementChip>
      )}

      {hasShare && (
        <EngagementChip
          interactive={Boolean(handlers.onShare)}
          onClick={() => handlers.onShare?.()}
          ariaLabel={labels.shareAriaLabel.replace(
            "{count}",
            String(item.shareCount ?? 0),
          )}
        >
          <Share2 className="size-3.5" aria-hidden />
          {item.shareCount !== undefined && (
            <span className="text-xs font-medium">
              {formatCount(item.shareCount)}
            </span>
          )}
        </EngagementChip>
      )}
    </div>
  );
}

interface EngagementChipProps {
  interactive: boolean;
  onClick: () => void;
  ariaLabel: string;
  active?: boolean;
  activeTone?: string;
  children: React.ReactNode;
}

function EngagementChip({
  interactive,
  onClick,
  ariaLabel,
  active,
  activeTone,
  children,
}: EngagementChipProps) {
  const baseClass = cn(
    "inline-flex h-11 min-w-11 items-center gap-1 rounded-md px-2 text-muted-foreground transition-colors",
    active && activeTone,
  );

  if (interactive) {
    return (
      <button
        type="button"
        onClick={(e) => {
          e.stopPropagation();
          e.preventDefault();
          onClick();
        }}
        aria-label={ariaLabel}
        aria-pressed={active}
        className={cn(
          baseClass,
          "cursor-pointer hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        )}
      >
        {children}
      </button>
    );
  }

  return (
    <span className={baseClass} aria-label={ariaLabel}>
      {children}
    </span>
  );
}

"use client";

import { MoreHorizontal } from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";

// F-S1 lock: cross-procomp imports use RELATIVE paths to specific files.
import type { CommentMenuItem } from "../../comment-thread-01/types";

interface NewsKebabProps {
  items: CommentMenuItem[];
  /** aria-label for the trigger button. Default "Open menu". */
  triggerAriaLabel?: string;
  className?: string;
}

/**
 * Kebab dropdown shared across all 5 variant parts (except `small`, which
 * skips kebab per Q-PA matrix). Renders a 44×44 touch target with vertical
 * ellipsis icon; the menu opens via shadcn DropdownMenu.
 *
 * Items shape comes from `CommentMenuItem` (reused from comment-thread-01,
 * same as post-card-01's kebab pattern). `separatorBefore: true` injects a
 * `<DropdownMenuSeparator>` above the item.
 *
 * **F-cross-13 defensive pattern (per memory):** uses `<DropdownMenuTrigger>`
 * directly with the trigger button as its child (no `asChild` to avoid
 * Base UI's Slot composition surface). All callback contravariance handled
 * by the items' `onClick` lambdas.
 *
 * Returns `null` when `items` is empty — caller's responsibility to skip
 * rendering the kebab cluster entirely when no items.
 */
export function NewsKebab({
  items,
  triggerAriaLabel = "Open menu",
  className,
}: NewsKebabProps) {
  if (items.length === 0) return null;

  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        aria-label={triggerAriaLabel}
        className={cn(
          "relative z-10 inline-flex h-11 w-11 cursor-pointer items-center justify-center rounded-full text-muted-foreground transition-colors hover:bg-accent hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
          className,
        )}
      >
        <MoreHorizontal className="size-5" aria-hidden />
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        {items.map((it, idx) => (
          <KebabRow
            key={`${it.label}-${idx}`}
            item={it}
            isFirst={idx === 0}
          />
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

interface KebabRowProps {
  item: CommentMenuItem;
  isFirst: boolean;
}

function KebabRow({ item, isFirst }: KebabRowProps) {
  return (
    <>
      {item.separatorBefore && !isFirst && <DropdownMenuSeparator />}
      <DropdownMenuItem
        disabled={item.disabled}
        onClick={(e) => {
          e.stopPropagation();
          item.onClick?.();
        }}
        className={cn(
          item.destructive &&
            "text-destructive focus:text-destructive focus:bg-destructive/10",
        )}
      >
        {item.icon}
        <span>{item.label}</span>
      </DropdownMenuItem>
    </>
  );
}
